def validate_cart_items(cart_items):
    for item in cart_items:
        if item['quantity'] <= 0:
            return False, "Invalid quantity for item: {}".format(item['name'])
        if item['price'] < 0:
            return False, "Invalid price for item: {}".format(item['name'])
    return True, ""

def apply_discount_codes(cart_total, discount_code, user):
    discounts = {'SAVE10': 0.1, 'PREMIUM20': 0.2, 'ADMIN30': 0.3}
    admin_only = ['ADMIN30']
    premium_only = ['PREMIUM20']
    
    if discount_code in discounts:
        if discount_code in admin_only and not user.get('is_admin', False):
            return False, "Discount code is admin only"
        if discount_code in premium_only and user.get('tier', '') != 'premium':
            return False, "Discount code is for premium users only"
        return cart_total * (1 - discounts[discount_code]), ""
    return cart_total, ""

def calculate_tax(cart_total, tax_rate):
    return cart_total * (1 + tax_rate)

def process_payment(cart_total, payment_info):
    # Dummy payment processing logic
    if payment_info.get('valid', False):
        return True, ""
    return False, "Payment failed"

def create_order_record(user, cart_items, total):
    return {
        'user_id': user['id'],
        'items': cart_items,
        'total': total,
        'status': 'completed'
    }

def checkout_process(cart_items, discount_code, user, tax_rate, payment_info):
    valid, msg = validate_cart_items(cart_items)
    if not valid:
        return msg
    
    cart_total = sum(item['price'] * item['quantity'] for item in cart_items)
    cart_total, msg = apply_discount_codes(cart_total, discount_code, user)
    if not isinstance(cart_total, float):
        return msg
    
    cart_total = calculate_tax(cart_total, tax_rate)
    
    success, msg = process_payment(cart_total, payment_info)
    if not success:
        return msg
    
    order_record = create_order_record(user, cart_items, cart_total)
    return order_record

